const uniq = <T,>(arr: T[]): T[] => Array.from(new Set(arr));

export const allRegions = uniq(sourceCatalog.map(s => s.region).filter(Boolean)).sort();
export const allSourceTypes = uniq(sourceCatalog.map(s => s.sourceType)).sort();
export const allWorkflows = uniq(sourceCatalog.flatMap(s => s.workflows)).sort();

export function filterSources(opts: {
  regions?: string[]; countries?: string[];
  sourceTypes?: string[]; sourceNames?: string[];
  workflows?: string[];
}): SourceRecord[] {
  return sourceCatalog.filter(s => {
    if (opts.regions?.length && !opts.regions.includes(s.region)) return false;
    if (opts.countries?.length && !opts.countries.includes(s.country)) return false;
    if (opts.sourceTypes?.length && !opts.sourceTypes.includes(s.sourceType)) return false;
    if (opts.sourceNames?.length && !opts.sourceNames.includes(s.sourceName)) return false;
    if (opts.workflows?.length && !s.workflows.some(w => opts.workflows!.includes(w))) return false;
    return true;
  });
}
